// Class definition (Blueprint)
class Rectangle {
private: // Data hiding (Encapsulation)
 int length;
 int width;

public: // Public interface
 // Constructor
 Rectangle() {
 length = 0;
 width = 0;
 }

 // Setter methods
 void setDimensions(int l, int w) {
 length = l;
 width = w;
 }

 // Member function (Method)
 int calculateArea() {
 return length * width;
 }

 // Destructor
 ~Rectangle() {
 // Cleanup code
 }
};

int main() {
 // Creating Objects (instances)
 Rectangle rect1; // Object on stack
 Rectangle *rect2 = new Rectangle(); // Dynamic object

 // Using object methods
 rect1.setDimensions(5, 3);
 int area1 = rect1.calculateArea(); // area1 = 15

 rect2->setDimensions(10, 4);
 int area2 = rect2->calculateArea(); // area2 = 40

 delete rect2; // Call destructor
 return 0;
}
